export const ImportDecisionAction = {
  skip: "skip",
  create: "create",
  merge: "merge",
} as const;

/**
 * Per-candidate resolution for a detected duplicate. action=skip discards the row, action=create forces a new record even if a match exists, action=merge updates the chosen existing employee with the candidate's selected fields.
 */
export interface ImportDecision {
  action: ImportDecisionAction;
  /** Required when action=merge. The existing employee ID to merge the candidate into. */
  mergeIntoId?: number;
  /** When action=merge, list of candidate fields to apply onto the existing employee (firstName, lastName, title, email, phone, department, location, startDate, bio). */
  fields?: string[];
}

