  /** When true, each group's owners (who are also being imported) are added as secondary (dotted-line) managers for that group's members. */
  useGroupOwnersAsSecondaryManagers?: boolean;
  /** Optional map keyed by Entra user ID with an ImportDecision describing how to resolve a detected duplicate. */
  decisions?: EntraImportRequestDecisions;
